  ('promotion-e3452428-moex-00129', 'promotion-e3452428', 'promotion-e3452428-moex-110-b96fcbef', 'sub-promotion-e3452428-02', NULL, 'essay', '甲男與乙女為上下樓層之鄰居，常有嫌隙。乙常在自家陽台澆花。一日
乙見甲在樓下抽菸，便將水往樓下灑，甲抬頭看見乙，覺得乙澆花灑水
是故意針對自己，便大罵：「你不要臉啦，故意澆我身上。有膽就直接來
找我。」乙認為甲謾罵傷害她，遂提告請求賠償。請依據民法規定，說
明其提告是否有理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:39+00:00", "source_pdf_sha1": "6df768ede210", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "102", "s": "0503", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "一般民政"}'::jsonb, NULL),
